129→fn parse_args<I>(args: I) -> Result<Command, String>
130→where
131→    I: IntoIterator<Item = String>,
132→{
133→    let mut args = args.into_iter();
134→    let _program = args.next();
135→
136→    match args.next().as_deref() {
137→        Some("--version" | "-V") => Ok(Command::Version),
138→        Some("--help" | "-h" | "help") => Ok(Command::Help),
139→        Some("list") => {
140→            let path = match args.next() {
141→                Some(p) => PathBuf::from(p),
142→                None => std::env::current_dir().map_err(|e| e.to_string())?,
143→            };
144→            Ok(Command::List { path })
145→        }
146→        Some("finalize") => {
147→            let opts = parse_finalize_args(&mut args)?;
148→            Ok(Command::Finalize(opts))
149→        }
150→        Some(other) => Err(format!("unknown command: {other}\n\n{USAGE}")),
151→        None => Ok(Command::Help),
152→    }
153→}
