155→fn list(path: &Path) -> Result<(), Box<dyn std::error::Error>> {
156→    let config = StackedConfig::with_defaults();
157→    let settings = UserSettings::from_config(config)?;
158→    let store_factories = StoreFactories::default();
159→    let working_copy_factories = default_working_copy_factories();
160→
161→    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
162→    let repo = workspace.repo_loader().load_at_head().block_on()?;
163→
164→    let expression = RevsetExpression::all();
165→    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
166→    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
167→    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
168→    let revset = resolved.evaluate(repo.as_ref())?;
169→
170→    let root_commit_id = repo.store().root_commit_id().clone();
171→
172→    for result in revset.iter() {
173→        let commit_id = result?;
174→        if commit_id == root_commit_id {
175→            continue;
176→        }
177→        let commit = repo.store().get_commit(&commit_id)?;
178→
179→        let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
180→        let change_short = &change_hex[..change_hex.len().min(12)];
181→
182→        let commit_hex = commit.id().hex();
183→        let commit_short = &commit_hex[..commit_hex.len().min(12)];
184→
185→        let first_line = commit.description().lines().next().unwrap_or("");
186→
187→        println!("{} {} {}", change_short, commit_short, first_line);
188→    }
189→
190→    Ok(())
191→}
192→
193→fn log_msg(log: &Path, msg: &str) {
194→    let nanos = std::time::SystemTime::now()
195→        .duration_since(std::time::UNIX_EPOCH)
196→        .unwrap_or_default()
197→        .as_nanos();
198→    let pid = std::process::id();
199→    let line = format!("[{nanos}] pid={pid} {msg}\n");
200→    if let Ok(mut f) = std::fs::OpenOptions::new()
201→        .create(true)
202→        .append(true)
203→        .open(log)
204→    {
205→        let _ = f.write_all(line.as_bytes());
206→    }
207→}
