209→fn finalize_exec(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
210→    log_msg(&opts.log, &format!("finalize_exec: starting opts={opts:?}"));
211→    // TODO 0.6.0: implement squash + push logic
212→    log_msg(&opts.log, "finalize_exec: done (stub)");
213→    Ok(())
214→}
