216→fn build_exec_args(opts: &FinalizeOpts) -> Vec<String> {
217→    let mut args = vec![
218→        "finalize".to_string(),
219→        "--exec".to_string(),
220→        "--repo".to_string(),
221→        opts.repo.to_string_lossy().to_string(),
222→        "--source".to_string(),
223→        opts.source.clone(),
224→        "--target".to_string(),
225→        opts.target.clone(),
226→        "--delay".to_string(),
227→        opts.delay_secs.to_string(),
228→        "--log".to_string(),
229→        opts.log.to_string_lossy().to_string(),
230→    ];
231→    if opts.push {
232→        args.push("--push".to_string());
233→    }
234→    args
235→}
236→
237→/// Spawn a detached child process with `--exec` and return immediately.
238→/// The child re-enters `main()`, parses `--exec`, and `finalize()` routes
239→/// it to `finalize_exec()` where the actual work happens.
240→fn daemonize(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
241→    log_msg(
242→        &opts.log,
243→        &format!("daemonize: parent starting opts={opts:?}"),
244→    );
245→
246→    let exe = std::env::current_exe()?;
247→    let args = build_exec_args(opts);
248→    log_msg(&opts.log, &format!("daemonize: exe={exe:?} args={args:?}"));
249→
250→    let mut cmd = std::process::Command::new(exe);
251→    cmd.args(&args).stdin(Stdio::null());
252→
253→    #[cfg(unix)]
254→    {
255→        use std::os::unix::process::CommandExt;
256→        unsafe {
257→            cmd.pre_exec(|| {
258→                libc::setsid();
259→                Ok(())
260→            });
261→        }
262→    }
263→
264→    let child = cmd.spawn()?;
265→    log_msg(
266→        &opts.log,
267→        &format!("daemonize: spawned child pid={}", child.id()),
268→    );
269→    eprintln!(
270→        "finalize: daemonized (pid {}), log: {}",
271→        child.id(),
272→        opts.log.display()
273→    );
274→    Ok(())
275→}
276→
277→fn finalize(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
278→    log_msg(&opts.log, &format!("finalize: entry opts={opts:?}"));
279→    let result = if opts.foreground || opts.exec {
280→        finalize_exec(opts)
281→    } else {
282→        daemonize(opts)
283→    };
284→    match &result {
285→        Ok(()) => log_msg(&opts.log, "finalize: exit ok"),
286→        Err(e) => log_msg(&opts.log, &format!("finalize: exit err={e}")),
287→    }
288→    result
289→}
290→
291→fn main() -> ExitCode {
292→    let cmd = match parse_args(std::env::args()) {
293→        Ok(cmd) => cmd,
294→        Err(e) => {
295→            eprintln!("error: {e}");
296→            return ExitCode::FAILURE;
297→        }
298→    };
299→
300→    match cmd {
301→        Command::Version => {
302→            println!("vc-x1 {}", env!("CARGO_PKG_VERSION"));
303→            ExitCode::SUCCESS
304→        }
305→        Command::Help => {
306→            println!("{USAGE}");
307→            ExitCode::SUCCESS
308→        }
309→        Command::List { path } => {
310→            if let Err(e) = list(&path) {
311→                eprintln!("error: {e}");
312→                return ExitCode::FAILURE;
313→            }
314→            ExitCode::SUCCESS
315→        }
316→        Command::Finalize(opts) => {
317→            log_msg(&opts.log, "main: finalize entry");
318→            match finalize(&opts) {
319→                Ok(()) => {
320→                    log_msg(&opts.log, "main: finalize exit ok");
321→                    ExitCode::SUCCESS
322→                }
323→                Err(e) => {
324→                    log_msg(&opts.log, &format!("main: finalize exit err={e}"));
325→                    eprintln!("error: {e}");
326→                    ExitCode::FAILURE
327→                }
328→            }
329→        }
330→    }
331→}
